        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def ortasini_bul(self):
        if self.head is None:
            return None

        slow = self.head
        fast = self.head

        while fast is not None and fast.next is not None:
            slow = slow.next
            fast = fast.next.next

        return slow.data

    def ekle(self, data):
